def even_ele(nested):
    """
    Recursively traverse a nested structure (tuples, lists, etc.) and
    return a tuple containing all even integers found.
    """
    evens = []

    def _extract(item):
        if isinstance(item, (list, tuple)):
            for sub in item:
                _extract(sub)
        elif isinstance(item, int):
            if item % 2 == 0:
                evens.append(item)

    _extract(nested)
    return tuple(evens)
