def find_lists(t):
    """
    Count all list objects that appear inside the given tuple `t`.
    The count includes lists that are nested inside other lists or tuples.
    """
    def _count(obj):
        count = 0
        if isinstance(obj, list):
            count += 1
        if isinstance(obj, (list, tuple)):
            for item in obj:
                count += _count(item)
        return count

    return _count(t)
