def find_fixed_point(arr):
    """
    Find a fixed point in the array, i.e., an index i such that arr[i] == i.
    If multiple fixed points exist, the first one found is returned.
    If no fixed point exists, returns -1.

    The function works for both sorted and unsorted arrays:
    - If the array is sorted in ascending order, a binary search is used
      for O(log n) time.
    - Otherwise, a linear scan is performed for O(n) time.
    """
    n = len(arr)
    if n == 0:
        return -1

    # Helper to check if array is sorted ascending
    def is_sorted(a):
        for i in range(1, len(a)):
            if a[i] < a[i - 1]:
                return False
        return True

    if is_sorted(arr):
        # Binary search for fixed point
        low, high = 0, n - 1
        while low <= high:
            mid = (low + high) // 2
            if arr[mid] == mid:
                return mid
            elif arr[mid] < mid:
                low = mid + 1
            else:
                high = mid - 1
        return -1
    else:
        # Linear scan for unsorted array
        for i, val in enumerate(arr):
            if val == i:
                return i
        return -1
```

